${((outputs) => {
// use the describeTable query to get the table key structure
const keyDefinitions = describeTable.outputs[0].AttributeDefinitions;

return outputs.Items?.map((i) => {
    // flatten table entries for better readablity
    const flatObject = Object.fromEntries(
        Object.entries(i).map(([k, o]) => {
            const v = Object.values(o).pop();
            return [k, v];
        }),
    );

    // generate the resuable key object as a hidden column in the table to be used in other queries
    const key = Object.fromEntries(
        keyDefinitions.map((def) => {
            const key = def.AttributeName;
            const value = {
                [def.AttributeType]: flatObject[key],
            };
            return [key, value];
        }),
    );
    return {
        ...flatObject,
        key,
    };
});

