${nullSafeFilters.value.map((filter, index) => {
    let conditionStatement = '';
    const n = `n${index}`;
    const v = `v${index}`;
    switch(filter.condition) {
        case 'begins_with':
        case 'NOT contains':
        case 'contains':{
            conditionStatement = `${filter.condition}(#${n}, :${v})`;
            break;
        }
        case '<=':
        case '<':
        case '>=':
        case '>':
        case '<>':
        case '=':{
            conditionStatement = `#${n} ${filter.condition} :${v}`;
            break;
        }
        case 'attribute_not_exists':
        case 'attribute_exists':{
            conditionStatement = `${filter.condition}(#${n})`;
            break;
        }

    }
    return conditionStatement
}).join(" AND ")}

